import{_ as a,o as t,c as s,a2 as d}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/configuration.md","filePath":"fr/guide/configuration.md"}'),i={name:"fr/guide/configuration.md"};function o(n,e,r,c,l,p){return t(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><p>Clearance est fourni avec des valeurs par défaut sensées, il fonctionne donc dès la sortie de la boîte après l&#39;<a href="/clearance-docs/fr/guide/installation.html">installation</a>. Publiez le fichier de configuration lorsque vous devez personnaliser le préfixe de route, le middleware, les modèles contextuels, ou tout autre paramètre.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Cela publie <code>config/clearance.php</code>.</p><h2 id="reference-de-configuration" tabindex="-1">Référence de configuration <a class="header-anchor" href="#reference-de-configuration" aria-label="Permalink to &quot;Référence de configuration&quot;">​</a></h2><p>Voici la référence définitive de chaque clé de <code>config/clearance.php</code>. Les autres pages de cette documentation renvoient ici plutôt que de répéter le tableau.</p><table tabindex="0"><thead><tr><th>Clé</th><th>Défaut</th><th>Rôle</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>Préfixe d&#39;URI pour toutes les routes du panneau.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>Appliqué à toutes les routes du panneau avant <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>Permission vérifiée par le middleware d&#39;accès.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>Par défaut, utilise <code>auth.providers.users.model</code>.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Interrupteur principal pour le module Utilisateurs (routes + composants Livewire).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - modèles pouvant servir de contextes de liaison de rôle.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>Impose la convention de nommage <code>group-action</code> des permissions.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>Caractère séparateur - <code>&#39;-&#39;</code> ou <code>&#39;_&#39;</code> uniquement.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>Remplace les gardes auto-détectés depuis <code>config/auth.php</code>. Vide = auto-détection de tous.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>Drivers acceptés lors de l&#39;injection des gardes en base de données dans <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>Layout Blade pour les composants pleine page. <code>null</code> = layout par défaut de l&#39;application hôte (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>Assigne automatiquement le rôle par défaut configuré dans les Paramètres lors de l&#39;événement <code>Registered</code>.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>Optionnel : <code>super_admin</code> contourne toutes les vérifications de Gate à l&#39;échelle de l&#39;application.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = auto-détection via <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="convention-de-nommage-des-permissions" tabindex="-1">Convention de nommage des permissions <a class="header-anchor" href="#convention-de-nommage-des-permissions" aria-label="Permalink to &quot;Convention de nommage des permissions&quot;">​</a></h2><p>Les permissions doivent suivre le format <code>group-action</code> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Désactivez le contrôle par environnement avec <code>enforce_naming_convention</code> :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Le séparateur est validé au démarrage</p><p>La valeur <code>naming_separator</code> est le seul élément de cette configuration qui atteint un fragment SQL brut (regroupement/tri des permissions), c&#39;est pourquoi seuls <code>-</code> ou <code>_</code> sont acceptés.</p></div><h2 id="personnaliser-le-middleware" tabindex="-1">Personnaliser le middleware <a class="header-anchor" href="#personnaliser-le-middleware" aria-label="Permalink to &quot;Personnaliser le middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Les noms de route restent stables quels que soient les changements de préfixe ou de middleware - voir le <a href="/clearance-docs/fr/guide/quick-start.html">Démarrage rapide</a> pour le tableau complet des routes.</p><h2 id="voir-aussi" tabindex="-1">Voir aussi <a class="header-anchor" href="#voir-aussi" aria-label="Permalink to &quot;Voir aussi&quot;">​</a></h2><ul><li><a href="/clearance-docs/fr/guide/quick-start.html">Démarrage rapide</a> - monter le panneau avec ces paramètres appliqués</li><li><a href="/clearance-docs/fr/guide/publishing.html">Publication des assets</a> - publier les traductions et comprendre la clé <code>layout</code></li><li><a href="/clearance-docs/fr/features/guards.html">Gardes</a> - comment <code>guards</code> et <code>allowed_guard_drivers</code> sont utilisés</li><li><a href="/clearance-docs/fr/features/super-admin.html">Super Admin</a> - comment fonctionne <code>super_admin_gate_bypass</code></li></ul>`,18)])])}const g=a(i,[["render",o]]);export{h as __pageData,g as default};
